<script>
import QRCodeModal from "@/components/QRCodeModal.vue";
import {warpnetService} from "@/service/service";

export default {
  name: "SideNav",
  components: {
    QRCodeModal,
  },
  data() {
    return {
      dropdown: false,
      profile: {},
      newMessages: 0,
      newNotifications: 0,
      qrModalOpen: false,
      qrCode: "",
      unsubscribeNotifications: null,
    };
  },
  mounted() {
    const theme = localStorage.getItem("theme");
    if (theme === "dark" || (!theme && window.matchMedia("(prefers-color-scheme: dark)").matches)) {
      document.documentElement.classList.add("dark");
    } else {
      document.documentElement.classList.remove("dark");
    }
  },
  methods: {
    async open(target) {
      const current = this.$route.name;
      if (
        target !== current ||
        this.$route.params.id !== this.profile.user_id
      ) {
        this.$router.push({
          name: target,
          params: {
            id: this.profile.user_id,
          },
        });
      }
    },
    async openTweetCompose() {
      await this.$router.push({
        name: 'Home',
        query: { compose: Date.now().toString() },
      });
    },
    toggleDarkMode() {
      const html = document.documentElement;
      if (html.classList.contains("dark")) {
        html.classList.remove("dark");
        localStorage.setItem("theme", "light");
      } else {
        html.classList.add("dark");
        localStorage.setItem("theme", "dark");
      }
    },
    signInByQR() {
        // warpnetService.getQR() is a synchronous in-memory lookup,
        // no await needed.
        this.qrCode = warpnetService.getQR();
        this.qrModalOpen = true;
    },
    async closeQR() {
      this.qrModalOpen = false
    },
    async signOut() {
      this.dropdown = false;
      try {
        await warpnetService.logoutUser();
      } catch (err) {
        console.error('Failed to sign out:', err);
      }
      this.$router.push({ name: 'Root' });
    },
  },
  async created() {
    console.log("loading component:", this.$options.name);
    this.profile = warpnetService.getOwnerProfile();

    // Root.vue sets this flag right after a first-run signup. Open
    // the QR pairing dialog so a brand-new user sees the visual
    // explainer without having to dig through the side-nav dropdown.
    //
    // Done first and in its own try/catch so a later avatar /
    // notifications failure can't suppress the onboarding — for a
    // first-run user the pairing UI is the most important thing this
    // mount is supposed to surface. Routed through signInByQR() so
    // there's a single code path opening the modal.
    try {
      if (typeof sessionStorage !== "undefined" &&
          sessionStorage.getItem("warpnet:show-pairing-onboarding") === "1") {
        sessionStorage.removeItem("warpnet:show-pairing-onboarding");
        await this.signInByQR();
      }
    } catch (error) {
      console.error("Failed to open pairing onboarding:", error);
    }

    const fullProfile = await warpnetService.getProfile(this.profile.user_id);
    try {
      if (fullProfile && !fullProfile.code && fullProfile.avatar_key) {
        this.profile.avatar = await warpnetService.getImage({userId:this.profile.user_id, key:fullProfile.avatar_key});
      } else {
        this.profile.avatar = null;
      }
    } catch (error) {
      console.error("Failed to load full profile:", error);
      this.profile.avatar = null;
    }

    this.unsubscribeNotifications = warpnetService.subscribeNotifications((resp) => {
      this.newNotifications = resp.unread_count || 0;
    });

    const resp = await warpnetService.getNotifications(true)
    if (resp) {
      this.newNotifications = resp.unread_count;
    }
  },
  beforeUnmount() {
    if (this.unsubscribeNotifications) {
      this.unsubscribeNotifications();
      this.unsubscribeNotifications = null;
    }
  },
};
</script>
